376→    if (allCapsSelected.length >= 2) {
377→      selected = allCapsSelected;
378→    } else if (allCapsSelected.length === 1) {
379→      selected = [selected.reduce((a, b) => (a.score > b.score ? a : b))];
380→    }
381→  }
382→
383→  // Cap at 3, sort by document position
384→  selected.sort((a, b) => a.position - b.position);
385→  selected = selected.slice(0, 3);
386→
387→  if (selected.length === 0) {
388→    return undefined;
389→  }
390→
391→  return selected.map((s) => s.text).join(" + ");
392→}
393→
394→/**
395→ * Extract potential recipe title from OCR text (sync heuristic fallback)
396→ */
397→export function extractTitle(text: string): string | undefined {
398→  if (!text || text.trim().length === 0) {
399→    return undefined;
400→  }
401→
402→  const lines = text.split("\n").map((line) => line.trim());
403→
404→  for (const line of lines) {
405→    if (line.length === 0) continue;
406→    if (line.length < 3 || line.length > 50) continue;
407→    if (looksLikeIngredient(line)) continue;
408→    if (isAllCaps(line)) continue;
409→    if (startsWithNumber(line)) continue;
410→    return line;
411→  }
412→
413→  return undefined;
414→}
